        return m[1].split(',').map(s => s.trim().replace(/^["']|["']$/g, '')).filter(Boolean);
    };
    return {
        summary: extract('summary') || '',
        key_files: extractList('key_files'),
        issues: extractList('issues'),
        recommendation: extract('recommendation') || '',
    };
}

