arguments.task:
Refactor activity-feed.ts to use immutable reducer pattern (P0 race condition fix from codebase audit). Then update subagent-runner.ts to use the new API.

## Problem
`activity-feed.ts` mutates state directly:
```ts
function addStep(state, label): void {
  state.steps.push({ label, completed: false, substeps: [] }); // MUTATION
}
```

This causes race conditions when `text_delta`, `tool_end`, and 80ms timer fire concurrently — three mutation paths hitting the same state object.

## Fix: Immutable Reducer Pattern

Each state mutation function returns NEW state instead of mutating in place. All state functions become pure:

### Changes to `activity-feed.ts`:

#### 1. `createActivityFeed()` — no change needed (returns new object)

#### 2. `addStep(state, label): ActivityFeedState`
```ts
export function addStep(state: ActivityFeedState, label: string): ActivityFeedState {
  if (label === "Working...") return state;

  for (let i = 0; i < state.steps.length; i++) {
    const existing = state.steps[i];
    if (label.startsWith(existing.label) && label.length > existing.label.length
      && existing.substeps.length === 0 && !existing.completed) {
      const newSteps = [...state.steps];
      newSteps[i] = { label, completed: false, substeps: [], startTime: existing.startTime };
      return { ...state, steps: newSteps };
    }
  }

  if (state.steps.some((s) => s.label === label)) return state;

  let steps = state.steps;
  let currentStep = state.currentStep;

  if (state.steps.length >= 6) { // MAX_FEED_STEPS
    steps = state.steps.slice(1); // shift
    if (currentStep > 0) currentStep--;
  }

  steps = [...steps, { label, completed: false, substeps: [], startTime: Date.now() }];
  if (currentStep === -1) currentStep = 0;

  return { ...state, steps, currentStep };
}
```

#### 3. `addSubstep(state, label): ActivityFeedState`
```ts
export function addSubstep(state: ActivityFeedState, label: string): ActivityFeedState {
  let { steps, currentStep } = state;

  if (currentStep >= 0 && currentStep < steps.length && steps[currentStep].completed) {
    return addStep(state, label);
  }

  if (currentStep < 0 || steps.length === 0) {
    if (steps.length === 0) {
      const stepLabel = label.length > 60 ? label.slice(0, 57) + "..." : label;
      steps = [{ label: stepLabel, completed: false, substeps: [], startTime: Date.now() }];
      currentStep = 0;
      return { ...state, steps, currentStep };
    }
  }

  if (currentStep < 0 || currentStep >= steps.length) return state;

  const step = steps[currentStep];
  if (step.substeps.some((s) => s.label === label)) return state;

  let newSubsteps = step.substeps;
  if (step.substeps.length >= 8) { // MAX_FEED_SUBSTEPS
    newSubsteps = step.substeps.slice(1);
  }

  newSubsteps = [...newSubsteps, { label, completed: false, startTime: Date.now() }];

  const newSteps = steps.map((s, i) => i === currentStep ? { ...s, substeps: newSubsteps } : s);
  return { ...state, steps: newSteps, currentStep };
}
```

#### 4. `completeLastSubstep(state, outputPreview?): ActivityFeedState`
```ts
export function completeLastSubstep(state: ActivityFeedState, outputPreview?: string): ActivityFeedState {
  if (state.currentStep < 0 || state.currentStep >= state.steps.length) return state;

  const step = state.steps[state.currentStep];
  if (step.substeps.length === 0) return state;

  const lastIdx = step.substeps.length - 1;
  const newSubsteps = step.substeps.map((sub, i) => {
    if (i === lastIdx) {
      return { 
        ...sub, 
        completed: true, 
        endTime: Date.now(),
        ...(outputPreview ? { outputPreview } : {})
      };
    }
    return sub;
  });

  const newSteps = state.steps.map((s, i) => i === state.currentStep ? { ...s, substeps: newSubsteps } : s);
  return { ...state, steps: newSteps };
}
```

#### 5. `completeCurrentStep(state): ActivityFeedState`
```ts
export function completeCurrentStep(state: ActivityFeedState): ActivityFeedState {
  if (state.currentStep < 0 || state.currentStep >= state.steps.length) return state;

  const now = Date.now();
  const newSteps = state.steps.map((s, i) => {
    if (i !== state.currentStep) return s;
    const newSubsteps = s.substeps.map(sub => ({
      ...sub,
      completed: true,
      endTime: sub.endTime || now,
    }));
    return { ...s, completed: true, endTime: now, substeps: newSubsteps };
  });

  return { ...state, steps: newSteps, currentStep: state.currentStep + 1 };
}
```

#### 6. `markFeedError(state, message): ActivityFeedState`
```ts
export function markFeedError(state: ActivityFeedState, message: string): ActivityFeedState {
  const now = Date.now();
  const newSteps = state.steps.map(step => ({
    ...step,
    completed: true,
    endTime: step.endTime || now,
    substeps: step.substeps.map(sub => ({
      ...sub,
      completed: true,
      endTime: sub.endTime || now,
    })),
  }));

  return {
    ...state,
    errored: true,
    errorMessage: message,
    steps: newSteps,
    currentStep: state.currentStep >= 0 ? newSteps.length : state.currentStep,
  };
}
```

#### 7. `retryFeedStep(state, reason?): { state: ActivityFeedState; retryCount: number }`
```ts
export function retryFeedStep(state: ActivityFeedState, reason?: string): { state: ActivityFeedState; retryCount: number } {
  const retryCount = ((state as any).retryCount || 0) + 1;
  const now = Date.now();

  const newSteps = state.steps.map(step => ({
    ...step,
    completed: false,
    endTime: undefined,
    startTime: now,
    substeps: step.substeps.map(sub => ({
      ...sub,
      completed: false,
      endTime: undefined,
      startTime: now,
    })),
  }));

  return {
    state: {
      ...state,
      errored: false,
      errorMessage: undefined,
      steps: newSteps,
      currentStep: 0,
      retryCount,
      retryReason: reason || state.errorMessage || "Unknown error",
    },
    retryCount,
  };
}
```

#### 8. `parseTextForFeed(state, text): ActivityFeedState`
This one is the most complex call path. It calls `addStep` internally. Convert it to immutable:

```ts
export function parseTextForFeed(state: ActivityFeedState, text: string): ActivityFeedState {
  let rawText = state.rawText + text;
  if (rawText.length > 10_000) { // MAX_RAW_TEXT
    const excess = rawText.length - 10_000;
    const firstNewline = rawText.indexOf("\n", excess);
    rawText = firstNewline >= 0 ? rawText.slice(firstNewline + 1) : rawText.slice(excess);
  }

  const lines = rawText.split("\n");
  const completeLines = lines.slice(0, -1);

  let currentState = { ...state, rawText };
  let inGoalSection = false;
  let inStepsSection = false;

  for (const line of completeLines) {
    const trimmed = line.trim();
    if (!trimmed) {
      inGoalSection = false;
      inStepsSection = false;
      continue;
    }

    if (trimmed.match(/^##\s+Goal/i)) {
      inGoalSection = true;
      inStepsSection = false;
      continue;
    }
    if (trimmed.match(/^##\s+Steps/i)) {
      inStepsSection = true;
      inGoalSection = false;
      continue;
    }
    if (/^#{1,3}\s+/.test(trimmed)) {
      inGoalSection = false;
      inStepsSection = false;
      continue;
    }

    if (inGoalSection && currentState.goal === "") {
      currentState = { ...currentState, goal: trimmed };
      continue;
    }

    if (inStepsSection) {
      // extractStepLabel logic (keep existing)
      const trimmed2 = trimmed;
      let label: string | null = null;
      if (trimmed2 && !trimmed2.startsWith("#")) {
        const bulletMatch = trimmed2.match(/^[-*•]\s+(.+)/);
        if (bulletMatch) label = bulletMatch[1].trim();
        else {
          const numMatch = trimmed2.match(/^\d+[.)]\s+(.+)/);
          if (numMatch) label = numMatch[1].trim();
        }
      }
      if (label && !currentState.steps.some((s) => s.label === label)) {
        currentState = addStep(currentState, label);
      }
      continue;
    }

    if (currentState.goal === "" && !trimmed.startsWith("#")) {
      currentState = { ...currentState, goal: trimmed };
    }
  }

  return currentState;
}
```

**IMPORTANT**: Keep all the existing helper functions unchanged:
- `createOrchestratorActivity()` 
- `addOrchestratorStep(activity, label)`
- `completeOrchestratorStep(activity)`
- `renderOrchestratorActivity(activity, goal?)`
- `renderCombinedProgress(...)` 
- `renderActivityFeed(name, state)`
- `renderSubstepLines(substeps, maxLines?)`
- `toolCallToSubstep(toolName, input)`
- `compressOutput(output)`
- `isValidStepLabel(label)`
- `isSectionHeader(line)`
- `extractStepLabel(line)` — keep as private helper, inline logic in parseTextForFeed

These render functions only READ state, they don't mutate. Keep them as-is.

### Changes to `subagent-runner.ts`:

All callers of the now-immutable functions need to reassign state:

1. Where `parseTextForFeed(feedState, text)` is called → `feedState = parseTextForFeed(feedState, text)`
2. Where `addSubstep(feedState, label)` is called → `feedState = addSubstep(feedState, label)`
3. Where `completeLastSubstep(feedState, preview)` is called → `feedState = completeLastSubstep(feedState, preview)`
4. Where `completeCurrentStep(feedState)` is called → `feedState = completeCurrentStep(feedState)`
5. Where `markFeedError(feedState, msg)` is called → `feedState = markFeedError(feedState, msg)`
6. Where `retryFeedStep(feedState, reason)` is called → `const result = retryFeedStep(feedState, reason); feedState = result.state;` (and use result.retryCount for display)

Search for ALL usages of these function calls in subagent-runner.ts and update them. Also search for any other file that calls these functions.

### Changes to `types.ts`:

Add `retryCount?: number` and `retryReason?: string` to the `ActivityFeedState` interface:
```ts
